 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 6	import { Button, ButtonVariant, Modal } from '@patternfly/react-core';
 7	
 8	type ConfirmVMActionModalProps = {
 9	  action: (vm: V1VirtualMachine) => Promise<string>;
10	  actionType: string;
11	  isOpen: boolean;
12	  onClose: () => void;
13	  vm: V1VirtualMachine;
14	};
15	
16	const ConfirmVMActionModal: FC<ConfirmVMActionModalProps> = ({
17	  action,
18	  actionType,
19	  isOpen,
20	  onClose,
21	  vm,
22	}) => {
23	  const { t } = useKubevirtTranslation();
24	
25	  const submitHandler = () => {
26	    action(vm);
27	    onClose();
28	  };
29	
30	  return (
31	    <Modal
32	      actions={[
33	        <Button key="confirm" onClick={submitHandler} variant={ButtonVariant.primary}>
34	          {t(actionType)}
35	        </Button>,
36	        <Button key="cancel" onClick={onClose} variant="link">
37	          {t('Cancel')}
38	        </Button>,
39	      ]}
40	      className="confirm-multiple-vm-actions-modal"
41	      isOpen={isOpen}
42	      onClose={onClose}
43	      onSubmit={submitHandler}
44	      title={t('{{actionType}} VirtualMachine?', { actionType })}
45	      variant={'small'}
46	    >
47	      {t(
48	        `Are you sure you want to ${actionType?.toLowerCase()} ${getName(
49	          vm,
50	        )} in namespace ${getNamespace(vm)}?`,
51	      )}
52	    </Modal>
53	  );
54	};
55	
56	export default ConfirmVMActionModal;

